import "./styles/AdminDashboard.css";
import { useNavigate } from "react-router-dom";

function AdminDashboard() {
  const navigate = useNavigate();

  return (
    <div className="admin-dashboard">
      <h1 className="admin-title">Admin Control Panel</h1>

      <div className="admin-cards">
        
<div
  className="admin-card"
  onClick={() => navigate("/admin/students")}
>
  <i class="bi bi-people"></i> Manage Students
</div>

        <div
          className="admin-card"
          onClick={() => navigate("/admin/manage-librarians")}
        >
          <i class="bi bi-person-workspace"></i> Manage Librarians
        </div>

        
<div
          className="admin-card"
          onClick={() => navigate("/admin/genres")}
        >
          <i class="bi bi-tags"></i> Manage Genres
        </div>
        <div
          className="admin-card"
          onClick={() => navigate("/admin/reports")}
        >
          <i class="bi bi-clipboard-data"></i> View Reports
        </div>

        <div
          className="admin-card"
          onClick={() => navigate("/admin/system")}
        >
          <i class="bi bi-gear"></i> System Overview
        </div>
      </div>
    </div>
  );
}

export default AdminDashboard;
